import React, { useState } from 'react';

import Icon from '@components/ui/Icon';

import * as styles from './faq.module.css';

/**
 * Displays a list of FAQs
 * @param {Object} prop - React prop passed to this component
 * @param {{q:String | JSX.Element,shortAns:String | JSX.Element,a:String | JSX.Element}[]} prop.faqs - Array of FAQ objects
 */
export default function FAQs({ faqs, className, ...restProps }) {
	if (!Array.isArray(faqs)) return;
	if (faqs.length < 1) return;
	return (
		<ul className={`${styles.faqUl}${className && typeof className === 'string' ? ' ' + className : ''}`} {...restProps}>
			{faqs.map((faq, i) => (
				<li key={'faq' + i}>
					<FAQ question={faq.q} shortAns={faq.shortAns} isCollapsed={i === 0 ? false : true}>
						{faq.a}
					</FAQ>
				</li>
			))}
		</ul>
	);
}

/**
 * Displays a single FAQ question-answer unit
 * @param {Object} prop - React prop passed to this component
 * @param {Boolean} [prop.isCollapsed=false] - Whether to show the FAQ unit collapsed. Default FALSE
 * @param {String | JSX.Element} prop.question - The question
 * @param {String | JSX.Element} prop.shortAns - Short answer for quick inference
 * @param {String | JSX.Element} prop.children - Detailed answer
 */
function FAQ({ isCollapsed, question, shortAns, children, ...restProps }) {
	const [isViz, setIsViz] = useState(!isCollapsed);
	return (
		<div className={`${styles.faqC}${isViz ? '' : ' ' + styles.isHid}`} {...restProps}>
			<header
				className={styles.hdr}
				onClick={() => {
					setIsViz(!isViz);
				}}
			>
				<div className={styles.qC}>
					<h3>{question}</h3>
					<div className={styles.shortAns}>{shortAns}</div>
				</div>
				{isViz ? <Icon icon="chevron-up" /> : <Icon icon="chevron-down" />}
			</header>
			<div className={styles.ans}>{children}</div>
		</div>
	);
}
